    def test_non_consecutive_duplicates_are_not_removed(self):
        # Function only removes adjacent duplicates, assuming sorted input
        assert deduplicate_sorted([1, 2, 1, 3]) == [1, 2, 1, 3]

    def test_none_values(self):
        assert deduplicate_sorted([None, None, 1, 1, 2]) == [None, 1, 2]

